INSERT [dbo].[EmailTemplates] ([Id], [Name], [Subject], [Description], [DefaultTemplate], [Template], [UpdatedBy], [UpdatedAt]) VALUES (2, N'Payment Success', N'Your Saffrat payment successful', N'<p>{OrderDate}, {PaymentMethod}, {InvoiceNo}, {TotalAmount}, {PaidAmount}, {DueAmount}, {Username}, {CompanyName}, {CompanyEmail}, {CompanyPhone}, {CompanyAddress}</p>', N'<p>Hi {Username},</p><p>Thank you for you order on Saffrat from {OrderDate} !</p><p>Following your successful payment, please find your invoice attached (in PDF format) to this email.</p><p>As you already performed payment, there is nothing else you need to do. However, we recommend you keep this for fututre reference.</p><p><b><span style="font-size: 18px;">Your Order</span></b></p><p>Order No.:&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{OrderNo}</span></p><p>Payment Method:&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{PaymentMethod}&nbsp;</span></p><p>Total Amount:&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{TotalAmount}&nbsp;</span></p><p>Paid Amount:&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{PaidAmount}</span></p><p>Due Amount: {DueAmount}&nbsp;</p><p><br></p><p style="text-align: center;">Problems or qustions? Call us at {CompanyPhone}</p><p style="text-align: center;">or email&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{CompanyEmail}</span></p><p style="text-align: center;"><span style="color: rgb(77, 81, 86); font-family: arial, sans-serif; white-space: nowrap; background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">©</span><span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">&nbsp;{CompanyName}&nbsp;</span><span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{CompanyAddress}</span></p>', N'<p>Hi {Username},</p><p>Thank you for you order on Saffrat from {OrderDate} !</p><p>Following your successful payment, please find your invoice attached (in PDF format) to this email.</p><p>As you already performed payment, there is nothing else you need to do. However, we recommend you keep this for fututre reference.</p><p><b><span style="font-size: 18px;">Your Order</span></b></p><p>Order No.:&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{OrderNo}</span></p><p>Payment Method:&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{PaymentMethod}&nbsp;</span></p><p>Total Amount:&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{TotalAmount}&nbsp;</span></p><p>Paid Amount:&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{PaidAmount}</span></p><p>Due Amount: {DueAmount}&nbsp;</p><p><br></p><p style="text-align: center;">Problems or qustions? Call us at {CompanyPhone}</p><p style="text-align: center;">or email&nbsp;<span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{CompanyEmail}</span></p><p style="text-align: center;"><span style="color: rgb(77, 81, 86); font-family: arial, sans-serif; white-space: nowrap; background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">©</span><span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">&nbsp;{CompanyName}&nbsp;</span><span style="background-color: var(--colorBackground); text-align: var(--bs-body-text-align);">{CompanyAddress}</span></p>', N'admin', CAST(N'2023-05-01T12:12:38.623' AS DateTime))
